/// Generated peer-ingress authority for standalone comms runtimes.
///
/// Session-backed runtimes use `PeerCommsHandle` against the live
/// MeerkatMachine authority. This generated adapter covers the same typed
/// peer-ingress facts for standalone hosts that do not have a session-owned DSL
/// handle, so classification, admission, and public phase never fall back to a
/// handwritten reducer.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct PeerIngressGeneratedAuthority {
    silent_request_intents: BTreeSet<String>,
}

impl Default for PeerIngressGeneratedAuthority {
    fn default() -> Self {
        Self::from_silent_intents(std::iter::empty::<String>())
    }
}

impl PeerIngressGeneratedAuthority {
    pub fn from_silent_intents<I, S>(silent_intents: I) -> Self
    where
        I: IntoIterator<Item = S>,
        S: Into<String>,
    {
        Self {
            silent_request_intents: silent_intents.into_iter().map(Into::into).collect(),
        }
    }

    pub fn classify_message(&self) -> PeerIngressClassification {
        PeerIngressClassification::required(
            PeerInputClass::ActionableMessage,
            PeerIngressKind::Message,
        )
    }

    pub fn classify_request_intent(&self, intent: &str) -> PeerIngressClassification {
        let auth = generated_auth_for_request_intent(intent);
        let mut classification = if let Some(kind) = generated_lifecycle_intent(intent) {
            generated_lifecycle_classification(kind)
        } else if self.silent_request_intents.contains(intent) {
            PeerIngressClassification::required(
                PeerInputClass::SilentRequest,
                PeerIngressKind::Request,
            )
        } else {
            PeerIngressClassification::required(
                PeerInputClass::ActionableRequest,
                PeerIngressKind::Request,
            )
        };
        classification.auth = auth;
        classification
    }

    pub fn classify_lifecycle(&self, kind: PeerLifecycleKind) -> PeerIngressClassification {
        generated_lifecycle_classification(kind)
    }

    pub fn classify_response(&self, status: ResponseStatus) -> PeerIngressClassification {
        let (class, terminality) = generated_response_classification(status);
        let mut classification =
            PeerIngressClassification::required(class, PeerIngressKind::Response);
        classification.response_terminality = Some(terminality);
        classification
    }

    pub fn classify_ack(&self) -> PeerIngressClassification {
        PeerIngressClassification::required(PeerInputClass::Ack, PeerIngressKind::Ack)
    }

    pub fn classify_plain_event(&self) -> PeerIngressClassification {
        PeerIngressClassification::required(PeerInputClass::PlainEvent, PeerIngressKind::PlainEvent)
    }

    pub fn classify_external_envelope(
        &self,
        facts: &PeerIngressEnvelopeFacts,
    ) -> PeerIngressAdmission {
        match &facts.kind {
            PeerIngressEnvelopeKind::Message { body } => {
                let classification = self.classify_message();
                PeerIngressAdmission {
                    rendered_text: format_peer_message_projection(&facts.from_peer, body),
                    classification,
                    lifecycle_peer: None,
                    request_id: None,
                }
            }
            PeerIngressEnvelopeKind::Request { intent, params } => {
                let classification = self.classify_request_intent(intent);
                let lifecycle_peer = classification
                    .lifecycle_kind
                    .map(|_| generated_lifecycle_subject(params, facts.from_peer.as_str()));
                let rendered_text = render_peer_ingress_admitted_text(facts, &classification);
                PeerIngressAdmission {
                    classification,
                    lifecycle_peer,
                    request_id: Some(facts.item_id.clone()),
                    rendered_text,
                }
            }
            PeerIngressEnvelopeKind::Lifecycle { kind, params } => {
                let classification = self.classify_lifecycle(*kind);
                PeerIngressAdmission {
                    rendered_text: String::new(),
                    classification,
                    lifecycle_peer: Some(generated_lifecycle_subject(
                        params,
                        facts.from_peer.as_str(),
                    )),
                    request_id: None,
                }
            }
            PeerIngressEnvelopeKind::Response {
                in_reply_to,
                status,
                result,
            } => {
                let classification = self.classify_response(*status);
                PeerIngressAdmission {
                    rendered_text: format_peer_response_projection(
                        &facts.from_peer,
                        in_reply_to,
                        *status,
                        result,
                    ),
                    classification,
                    lifecycle_peer: None,
                    request_id: Some(in_reply_to.clone()),
                }
            }
            PeerIngressEnvelopeKind::Ack { in_reply_to } => {
                let classification = self.classify_ack();
                PeerIngressAdmission {
                    rendered_text: format_peer_ack_projection(&facts.from_peer, in_reply_to),
                    classification,
                    lifecycle_peer: None,
                    request_id: Some(in_reply_to.clone()),
                }
            }
        }
    }

    pub fn classify_plain_event_facts(
        &self,
        facts: &PeerIngressPlainEventFacts,
    ) -> PeerIngressAdmission {
        PeerIngressAdmission {
            classification: self.classify_plain_event(),
            lifecycle_peer: None,
            request_id: None,
            rendered_text: format_external_event_projection(&facts.source_name, Some(&facts.body)),
        }
    }

    pub fn resolve_receive_authority(
        &self,
        facts: PeerIngressReceiveFacts,
    ) -> PeerIngressReceiveAuthority {
        let (outcome, admission_diagnostic, authority_phase) = if facts.queue_closed {
            (
                PeerIngressReceiveOutcome::DroppedSessionClosed,
                None,
                facts.current_phase,
            )
        } else if !facts.queue_capacity_available {
            (
                PeerIngressReceiveOutcome::DroppedInboxFull,
                None,
                facts.current_phase,
            )
        } else if facts.kind == PeerIngressKind::PlainEvent {
            (
                PeerIngressReceiveOutcome::Admitted,
                None,
                facts.current_phase,
            )
        } else {
            let admitted = facts.auth_exempt || facts.trusted || !facts.auth_required;
            let authority_phase = if admitted || facts.queued_work_present {
                PeerIngressAuthorityPhase::Received
            } else {
                PeerIngressAuthorityPhase::Dropped
            };
            let outcome = if admitted {
                PeerIngressReceiveOutcome::Admitted
            } else {
                PeerIngressReceiveOutcome::DroppedUntrustedSender
            };
            (
                outcome,
                Some(PeerIngressAdmissionDiagnostic::from_trusted(facts.trusted)),
                authority_phase,
            )
        };

        PeerIngressReceiveAuthority {
            outcome,
            admission_diagnostic,
            authority_phase,
        }
    }

    pub fn resolve_dequeue_authority(
        &self,
        current_phase: PeerIngressAuthorityPhase,
        facts: PeerIngressDequeueFacts,
    ) -> PeerIngressDequeueAuthority {
        let authority_phase = if facts.kind == PeerIngressKind::PlainEvent || facts.auth.is_exempt()
        {
            current_phase
        } else if facts.queued_work_remaining {
            PeerIngressAuthorityPhase::Received
        } else {
            PeerIngressAuthorityPhase::Delivered
        };

        PeerIngressDequeueAuthority { authority_phase }
    }
}

fn generated_auth_for_request_intent(intent: &str) -> PeerIngressAuthDecision {
    if intent == SUPERVISOR_BRIDGE_INTENT {
        PeerIngressAuthDecision::Exempt(PeerIngressAuthExemption::SupervisorBridge)
    } else {
        PeerIngressAuthDecision::Required
    }
}

fn generated_lifecycle_intent(intent: &str) -> Option<PeerLifecycleKind> {
    if intent == PeerLifecycleKind::PeerAdded.as_str() {
        Some(PeerLifecycleKind::PeerAdded)
    } else if intent == PeerLifecycleKind::PeerRetired.as_str() {
        Some(PeerLifecycleKind::PeerRetired)
    } else if intent == PeerLifecycleKind::PeerUnwired.as_str() {
        Some(PeerLifecycleKind::PeerUnwired)
    } else {
        None
    }
}

fn generated_lifecycle_classification(kind: PeerLifecycleKind) -> PeerIngressClassification {
    match kind {
        PeerLifecycleKind::PeerAdded => PeerIngressClassification {
            class: PeerInputClass::PeerLifecycleAdded,
            kind: PeerIngressKind::Request,
            auth: PeerIngressAuthDecision::Required,
            lifecycle_kind: Some(PeerLifecycleKind::PeerAdded),
            response_terminality: None,
        },
        PeerLifecycleKind::PeerRetired => PeerIngressClassification {
            class: PeerInputClass::PeerLifecycleRetired,
            kind: PeerIngressKind::Request,
            auth: PeerIngressAuthDecision::Required,
            lifecycle_kind: Some(PeerLifecycleKind::PeerRetired),
            response_terminality: None,
        },
        PeerLifecycleKind::PeerUnwired => PeerIngressClassification {
            class: PeerInputClass::PeerLifecycleUnwired,
            kind: PeerIngressKind::Request,
            auth: PeerIngressAuthDecision::Required,
            lifecycle_kind: Some(PeerLifecycleKind::PeerUnwired),
            response_terminality: None,
        },
    }
}

fn generated_lifecycle_subject(params: &serde_json::Value, fallback_peer: &str) -> String {
    params
        .get("peer")
        .and_then(serde_json::Value::as_str)
        .filter(|peer| !peer.is_empty())
        .unwrap_or(fallback_peer)
        .to_string()
}

fn generated_response_classification(status: ResponseStatus) -> (PeerInputClass, TerminalityClass) {
    match status {
        ResponseStatus::Accepted => (PeerInputClass::ResponseProgress, TerminalityClass::Progress),
        ResponseStatus::Completed => (
            PeerInputClass::ResponseTerminal,
            TerminalityClass::Terminal {
                disposition: TerminalDisposition::Completed,
            },
        ),
        ResponseStatus::Failed => (
            PeerInputClass::ResponseTerminal,
            TerminalityClass::Terminal {
                disposition: TerminalDisposition::Failed,
            },
        ),
    }
}
